#nullable enable // autogenerated

using MVZ2.GameContent.Damages;
using MVZ2.GameContent.Enemies;
using MVZ2Logic.Callbacks;
using PVZEngine.Buffs;
using PVZEngine.Callbacks;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Buffs.Enemies
{
    [AutoBuffDefinition(VanillaBuffNames.Enemy.controlRodUnstable)]
    public class ControlRodUnstableBuff : BuffDefinition
    {
        public ControlRodUnstableBuff(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(LogicLevelCallbacks.ENTITY_DEATH_EFFECTS, DeathEffectsCallback, filter: EntityTypes.ENEMY);
        }
        private void DeathEffectsCallback(LevelCallbacks.EntityDeathParams param, CallbackResult result)
        {
            var entity = param.entity;
            var buffCount = entity.GetBuffCount<ControlRodUnstableBuff>();
            if (buffCount <= 0)
                return;
            var effects = new DamageEffectList(VanillaDamageEffects.EXPLOSION, VanillaDamageEffects.DAMAGE_BODY_AFTER_ARMOR_BROKEN, VanillaDamageEffects.MUTE);
            Berserker.Explode(entity, DAMAGE_PER_BUFF * buffCount, RADIUS, effects, entity.GetFaction());
        }
        public const float DAMAGE_PER_BUFF = 300;
        public const float RADIUS = 120;
    }
}
